module pipeline_2stage (
    input rst,
    input [3:0] a,
    input [3:0] b,
    input [3:0] constant,
    output reg [3:0] stage1_out,
    output reg [3:0] stage2_out
);

    // Stage 1: Addition
    always @(posedge rst) begin
        stage1_out <= a + b;
    end

    // Stage 2: Subtraction
    always @(posedge rst) begin
        stage2_out <= stage1_out - constant;
    end
endmodule
